import React, { useState, useEffect, useRef } from 'react';
import styled from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

// Register ScrollTrigger
gsap.registerPlugin(ScrollTrigger);

const MobileContainer = styled.section`
  padding: var(--space-3xl) 0;
  background: var(--color-deep-purple);
  
  @media (min-width: 769px) {
    display: none;
  }
`;

const Container = styled.div`
  max-width: 100%;
  padding: 0 var(--space-lg);
  
  @media (max-width: 480px) {
    padding: 0 var(--space-md);
  }
`;

const Title = styled.h2`
  font-size: clamp(1.75rem, 7vw, 2.5rem);
  font-weight: 900;
  color: var(--color-text-primary);
  text-align: center;
  margin-bottom: var(--space-2xl);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  opacity: 0;
`;

const TabContainer = styled.div`
  display: flex;
  justify-content: center;
  gap: var(--space-sm);
  margin-bottom: var(--space-2xl);
  flex-wrap: wrap;
  opacity: 0;
`;

const TabButton = styled.button`
  padding: var(--space-sm) var(--space-lg);
  border-radius: var(--radius-full);
  border: 2px solid ${props => props.active ? 'var(--color-neon-purple)' : 'rgba(153, 69, 255, 0.3)'};
  background: ${props => props.active ? 'var(--color-neon-purple)' : 'transparent'};
  color: ${props => props.active ? 'white' : 'var(--color-light-purple)'};
  font-weight: 600;
  font-size: var(--text-sm);
  cursor: pointer;
  transition: all 0.3s ease;
  min-height: 44px;
  -webkit-tap-highlight-color: transparent;
  
  &:hover {
    background: ${props => props.active ? 'var(--color-neon-purple)' : 'rgba(153, 69, 255, 0.1)'};
    border-color: var(--color-neon-purple);
  }
  
  &:focus {
    outline: 2px solid var(--color-neon-purple);
    outline-offset: 2px;
  }
`;

const ServiceCard = styled(motion.div)`
  background: rgba(26, 0, 51, 0.6);
  border-radius: var(--radius-xl);
  border: 1px solid rgba(153, 69, 255, 0.2);
  overflow: hidden;
  padding: var(--space-2xl);
  
  @media (max-width: 480px) {
    padding: var(--space-xl);
  }
`;

const ServiceHeader = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-bottom: var(--space-2xl);
`;

const ServiceLogo = styled.div`
  width: 100px;
  height: 100px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: var(--space-lg);
  
  svg {
    width: 100%;
    height: 100%;
    filter: drop-shadow(0 0 20px var(--service-accent, var(--color-neon-purple)));
  }
`;

const ServiceTitle = styled.h3`
  font-size: clamp(1.5rem, 6vw, 2rem);
  font-weight: 800;
  color: var(--color-white);
  margin-bottom: var(--space-md);
`;

const ServiceDescription = styled.p`
  font-size: var(--text-base);
  color: var(--color-text-secondary);
  line-height: 1.6;
  text-align: center;
  margin-bottom: var(--space-xl);
  
  @media (max-width: 480px) {
    font-size: var(--text-sm);
  }
`;

const ServiceDetailsList = styled.ul`
  list-style: none;
  padding: 0;
  margin: 0;
  
  li {
    font-size: var(--text-sm);
    color: var(--color-text-secondary);
    margin-bottom: var(--space-sm);
    padding-left: var(--space-lg);
    position: relative;
    line-height: 1.6;
    
    &::before {
      content: '•';
      position: absolute;
      left: 0;
      color: var(--service-accent, var(--color-neon-purple));
      font-weight: bold;
    }
  }
`;

const ServicesMobile = ({ servicesData }) => {
  const [activeService, setActiveService] = useState(0);
  const containerRef = useRef(null);
  const titleRef = useRef(null);
  const tabsRef = useRef(null);
  const cardRef = useRef(null);
  
  useEffect(() => {
    const container = containerRef.current;
    const title = titleRef.current;
    const tabs = tabsRef.current;
    const card = cardRef.current;
    
    if (!container || !title || !tabs) return;
    
    // Create a context for all animations
    const ctx = gsap.context(() => {
      // Animate title on scroll
      gsap.fromTo(title, 
        { 
          opacity: 0, 
          y: 30 
        },
        {
          opacity: 1,
          y: 0,
          duration: 0.8,
          ease: "power2.out",
          scrollTrigger: {
            trigger: title,
            start: "top 80%",
            end: "bottom 20%",
            toggleActions: "play none none reverse"
          }
        }
      );
      
      // Animate tabs
      gsap.fromTo(tabs,
        {
          opacity: 0,
          y: 20
        },
        {
          opacity: 1,
          y: 0,
          duration: 0.6,
          delay: 0.2,
          ease: "power2.out",
          scrollTrigger: {
            trigger: tabs,
            start: "top 85%",
            end: "bottom 20%",
            toggleActions: "play none none reverse"
          }
        }
      );
      
      // Animate card on first appearance
      if (card) {
        gsap.fromTo(card,
          {
            opacity: 0,
            scale: 0.95,
            y: 30
          },
          {
            opacity: 1,
            scale: 1,
            y: 0,
            duration: 0.8,
            delay: 0.3,
            ease: "power2.out",
            scrollTrigger: {
              trigger: card,
              start: "top 85%",
              end: "bottom 20%",
              toggleActions: "play none none reverse"
            }
          }
        );
      }
    }, container);
    
    return () => {
      ctx.revert();
    };
  }, []);
  
  // Animate service details when they appear
  useEffect(() => {
    const card = cardRef.current;
    if (!card) return;
    
    const ctx = gsap.context(() => {
      const details = card.querySelectorAll('li');
      if (details.length > 0) {
        gsap.fromTo(details,
          {
            opacity: 0,
            x: -20
          },
          {
            opacity: 1,
            x: 0,
            duration: 0.4,
            stagger: 0.05,
            ease: "power2.out"
          }
        );
      }
    }, card);
    
    return () => {
      ctx.revert();
    };
  }, [activeService]);
  
  return (
    <MobileContainer ref={containerRef} id="services">
      <Container>
        <Title ref={titleRef}>Services</Title>
        
        <TabContainer ref={tabsRef}>
          {servicesData.map((service, index) => (
            <TabButton
              key={service.id}
              active={activeService === index}
              onClick={() => setActiveService(index)}
              aria-pressed={activeService === index}
              aria-label={`View ${service.title} service`}
            >
              {service.title}
            </TabButton>
          ))}
        </TabContainer>
        
        <AnimatePresence mode="wait">
          <ServiceCard
            ref={cardRef}
            key={activeService}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 0.3 }}
            style={{
              '--service-accent': 
                servicesData[activeService].id === 'fivem' ? '#FF6F00' : 
                servicesData[activeService].id === 'altv' ? '#008736' : 
                '#5865F2'
            }}
          >
            <ServiceHeader>
              <ServiceLogo>
                {servicesData[activeService].logo}
              </ServiceLogo>
              <ServiceTitle>{servicesData[activeService].title}</ServiceTitle>
            </ServiceHeader>
            
            <ServiceDescription>
              {servicesData[activeService].description}
            </ServiceDescription>
            
            <h4 style={{ 
              fontSize: 'var(--text-base)', 
              color: 'var(--color-text-primary)', 
              marginBottom: 'var(--space-md)',
              fontWeight: 600 
            }}>
              Meine Leistungen:
            </h4>
            <ServiceDetailsList>
              {servicesData[activeService].details.map((detail, index) => (
                <li key={index}>{detail}</li>
              ))}
            </ServiceDetailsList>
          </ServiceCard>
        </AnimatePresence>
      </Container>
    </MobileContainer>
  );
};

export default ServicesMobile;