import React, { useRef, useEffect, useState } from 'react';
import styled from 'styled-components';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { motion, AnimatePresence } from 'framer-motion';
import ServicesMobile from './ServicesMobile';

gsap.registerPlugin(ScrollTrigger);

const Container = styled.div`
  min-height: 400vh;
  position: relative;
  background: var(--color-deep-purple);
`;

const PinSection = styled.div`
  height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: ${props => `radial-gradient(circle at 30% 50%, ${props.$accent}15 0%, transparent 60%)`};
    transition: all 1s ease;
  }
`;

const SectionTitle = styled.h1`
  position: absolute;
  top: clamp(80px, 10vh, 120px);
  left: 50%;
  transform: translateX(-50%);
  font-size: clamp(2rem, 5vw, 4rem);
  font-weight: 900;
  color: var(--color-text-primary);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  z-index: 10;
  
  @media (max-width: 768px) {
    top: 80px;
    font-size: 2.5rem;
  }
  
  @media (max-width: 480px) {
    top: 60px;
    font-size: 2rem;
  }
`;

const Content = styled.div`
  max-width: 1400px;
  width: 90%;
  display: grid;
  grid-template-columns: 1.5fr 1fr;
  gap: 60px;
  align-items: center;
  
  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
    text-align: center;
  }
`;

const ServiceContent = styled(motion.div)`
  position: absolute;
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
`;

const ServiceInfo = styled(motion.div)`
  width: 100%;
`;

const Title = styled(motion.h1)`
  font-size: clamp(3rem, 8vw, 7rem);
  font-weight: 900;
  color: var(--color-text-primary);
  margin-bottom: 2rem;
  position: relative;
  
  &::after {
    content: '';
    position: absolute;
    bottom: -10px;
    left: 0;
    width: 100px;
    height: 4px;
    background: ${props => props.$accent};
  }
  
  @media (max-width: 1024px) {
    &::after {
      left: 50%;
      transform: translateX(-50%);
    }
  }
`;

const Description = styled(motion.p)`
  font-size: clamp(1.125rem, 2vw, 1.5rem);
  color: var(--color-text-secondary);
  opacity: 0.9;
  margin-bottom: 3rem;
  line-height: 1.8;
`;

const ServiceDetails = styled(motion.div)`
  background: rgba(255, 255, 255, 0.02);
  backdrop-filter: blur(10px);
  border-radius: 20px;
  padding: 2.5rem;
  border: 1px solid rgba(255, 255, 255, 0.05);
  
  h3 {
    font-size: 1.5rem;
    color: var(--color-text-primary);
    margin-bottom: 1.5rem;
    font-weight: 700;
  }
  
  ul {
    list-style: none;
    padding: 0;
    
    li {
      color: var(--color-text-secondary);
      margin-bottom: 1.2rem;
      padding-left: 2rem;
      position: relative;
      line-height: 1.6;
      font-weight: 500;
      
      &::before {
        content: '→';
        position: absolute;
        left: 0;
        color: ${props => props.$accent || '#667eea'};
        font-weight: bold;
      }
    }
  }
`;

const LogoContainer = styled(motion.div)`
  display: flex;
  justify-content: center;
  align-items: center;
  position: relative;
  
  svg {
    filter: drop-shadow(0 0 40px ${props => props.$accent}40);
    transition: all 0.15s ease;
    
    &:hover {
      transform: scale(1.05) rotate(5deg);
      filter: drop-shadow(0 0 60px ${props => props.$accent}60);
    }
  }
`;

const ProgressIndicator = styled.div`
  position: fixed;
  right: 50px;
  top: 50%;
  transform: translateY(-50%);
  z-index: 100;
  
  @media (max-width: 768px) {
    right: 20px;
  }
`;

const ProgressDot = styled.div`
  width: 12px;
  height: 12px;
  border-radius: 50%;
  margin: 20px 0;
  background: ${props => props.$active ? props.$accent : 'rgba(255,255,255,0.2)'};
  border: 2px solid ${props => props.$active ? props.$accent : 'rgba(255,255,255,0.3)'};
  transition: all 0.15s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;
  position: relative;
  
  &::after {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: ${props => props.$active ? '30px' : '0'};
    height: ${props => props.$active ? '30px' : '0'};
    border-radius: 50%;
    background: ${props => props.$accent};
    opacity: 0.3;
    transition: all 0.15s ease;
  }
  
  &:hover {
    transform: scale(1.2);
  }
`;

const Services = () => {
  const pinRef = useRef(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isMobile, setIsMobile] = useState(false);
  
  const servicesData = [
    {
      id: "fivem",
      title: "FiveM",
      accent: "#FF6F00",
      description: "With extensive experience in FiveM scripting, I specialize in creating custom solutions to enhance your server, from gameplay mechanics to server optimizations.",
      details: [
        "Fully custom scripts built from scratch to match unique server needs",
        "Optimized Lua scripting for smooth performance with high player counts",
        "Bug fixing, exploit patching, and performance issue resolution",
        "Core framework enhancements and modifications (ESX, QBCore, custom frameworks)",
        "Event-driven architecture for maintainable and scalable code",
        "Performance profiling and resource optimization",
      ],
      logo: (
        <svg version="1.1" xmlns="http://www.w3.org/2000/svg" viewBox="-768.1 533.9 210.2 240.1" width="300" height="300">
          <path
            fill="#FF6F00"
            d="M-766.9,774l-1.2-1.2c14.5-40.8,21.7-62.5,22.9-63.7l67.2-67.2c-2.4,10.8-15.6,54-37.2,132.1H-766.9z M-735.7,681.6h-1.2c2.4-8.4,6-14.4,12-19.2c19.2-19.2,38.4-38.4,57.6-56.4c-0.9,5.4-3.3,10.4-7.1,14.4L-735.7,681.6z M-709.2,602.4L-709.2,602.4c14.4-45.6,22.8-68.5,24-68.5h44.4C-657.6,550.8-680.4,573.6-709.2,602.4z M-722.5,643.1h-1.2c7.3-21.6,10.9-32.4,12.1-33.6l73.3-72.1c1.2,0,3.6,4.9,6,15.7L-722.5,643.1z M-658.8,604.7h-1.2c0-3.6-1.2-4.8-1.2-4.8v-1.2c9.6-10.9,21.7-21.7,33.6-32.4c1.2,1.2,1.2,3.6,1.2,4.8C-638.3,584.3-649.2,595.1-658.8,604.7L-658.8,604.7z M-559.2,774h-51.6c-1.2,0-4.8-12.1-10.8-33.6c-19.2-69.6-31.2-110.4-33.6-121.2l33.6-33.6h1.2c4.8,14.5,25.2,76.8,62.5,187.3L-559.2,774z"
          />
        </svg>
      ),
    },
    {
      id: "altv",
      title: "alt:V",
      accent: "#008736",
      description: "Building and optimizing scripts for alt:V, I provide high-performance solutions tailored to your server's needs and ensure seamless gameplay experiences.",
      details: [
        "High-performance TypeScript resource development tailored for alt:V",
        "Clean, maintainable code with strong type safety and modern ES features",
        "Optimized client-server communication using alt:V's networking API",
        "Scalable architecture for large, persistent multiplayer worlds",
        "Integration with REST, WebSocket, and database backends",
        "Performance profiling and resource optimization for minimal CPU and RAM usage",
      ],
      logo: (
        <svg fill="none" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="300" height="300">
          <path fillRule="evenodd" clipRule="evenodd" d="m40.31.5 387.23 56.53c22.2 3.24 42.07 24.22 44.5 46.85l39.72 370.85c2.39 22.33-13.31 38.96-35.2 37.13L95.1 480.1c-24.44-2.03-46.58-22.98-49.32-46.8L.28 37.68C-2.49 13.5 15.5-3.13 40.31.5Z" fill="#008736" />
          <path
            opacity=".15"
            fillRule="evenodd"
            clipRule="evenodd"
            d="m25.23 54.08 41.84 363.96c2.24 19.44 20.62 36.95 40.82 38.63l350.93 29.22c8.66.72 15.78-2.2 20.51-7.2 4.75-5.02 7.44-12.48 6.48-21.44L449.27 116.1c-2-18.6-18.58-36.03-36.69-38.68l-356.22-52c-10.14-1.49-18.4 1.21-23.8 6.23-5.39 4.99-8.45 12.73-7.33 22.44Zm-4.97.57L62.11 418.6c2.51 21.9 22.89 41.17 45.37 43.04l350.92 29.22c20.13 1.68 34.58-13.61 32.38-34.15l-36.54-341.16c-2.23-20.82-20.5-40.11-40.93-43.1l-356.23-52c-22.83-3.34-39.37 11.97-36.82 34.19Z"
            fill="#F1F2F2"
          />
          <path fillRule="evenodd" clipRule="evenodd" d="m143 158 113 196.18L369 158H218.43L256 223.52l18.83-32.43h37.47L256 288.52 180.76 158H143Z" fill="#F1F2F2" />
        </svg>
      ),
    },
    {
      id: "discord",
      title: "Discord",
      accent: "#5865F2",
      description: "From moderation bots to custom tools, I create Discord bots that integrate seamlessly with your community, providing essential features and automating server management.",
      details: [
        "Automated moderation systems with customizable rules and real-time logging",
        "Game server management tools with live status tracking and in-game integration",
        "Integration with APIs, databases, and external services for live data",
        "Role & permission management automation",
        "Event scheduling and announcement systems",
        "Custom verification flows (Steam, game accounts, playtime tracking, etc.)",
      ],
      logo: (
        <svg width="256" height="256" viewBox="0 -28.5 256 256" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid">
          <path
            d="M216.856339,16.5966031 C200.285002,8.84328665 182.566144,3.2084988 164.041564,0 C161.766523,4.11318106 159.108624,9.64549908 157.276099,14.0464379 C137.583995,11.0849896 118.072967,11.0849896 98.7430163,14.0464379 C96.9108417,9.64549908 94.1925838,4.11318106 91.8971895,0 C73.3526068,3.2084988 55.6133949,8.86399117 39.0420583,16.6376612 C5.61752293,67.146514 -3.4433191,116.400813 1.08711069,164.955721 C23.2560196,181.510915 44.7403634,191.567697 65.8621325,198.148576 C71.0772151,190.971126 75.7283628,183.341335 79.7352139,175.300261 C72.104019,172.400575 64.7949724,168.822202 57.8887866,164.667963 C59.7209612,163.310589 61.5131304,161.891452 63.2445898,160.431257 C105.36741,180.133187 151.134928,180.133187 192.754523,160.431257 C194.506336,161.891452 196.298154,163.310589 198.110326,164.667963 C191.183787,168.842556 183.854737,172.420929 176.223542,175.320965 C180.230393,183.341335 184.861538,190.991831 190.096624,198.16893 C211.238746,191.588051 232.743023,181.531619 254.911949,164.955721 C260.227747,108.668201 245.831087,59.8662432 216.856339,16.5966031 Z M85.4738752,135.09489 C72.8290281,135.09489 62.4592217,123.290155 62.4592217,108.914901 C62.4592217,94.5396472 72.607595,82.7145587 85.4738752,82.7145587 C98.3405064,82.7145587 108.709962,94.5189427 108.488529,108.914901 C108.508531,123.290155 98.3405064,135.09489 85.4738752,135.09489 Z M170.525237,135.09489 C157.88039,135.09489 147.510584,123.290155 147.510584,108.914901 C147.510584,94.5396472 157.658606,82.7145587 170.525237,82.7145587 C183.391518,82.7145587 193.761324,94.5189427 193.539891,108.914901 C193.539891,123.290155 183.391518,135.09489 170.525237,135.09489 Z"
            fill="#5865F2"
            fillRule="nonzero"
          />
        </svg>
      ),
    },
  ];
  
  useEffect(() => {
    setIsMobile(window.innerWidth <= 768);
    const handleResize = () => setIsMobile(window.innerWidth <= 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);
  
  useEffect(() => {
    if (isMobile) return;
    
    const element = pinRef.current;
    if (!element) return;
    
    const trigger = ScrollTrigger.create({
      trigger: element,
      start: "top top",
      end: "+=300%",
      pin: true,
      pinSpacing: true,
      scrub: true,
      onUpdate: (self) => {
        const index = Math.min(
          Math.floor(self.progress * servicesData.length),
          servicesData.length - 1
        );
        setCurrentIndex(index);
      }
    });
    
    return () => {
      trigger.kill();
    };
  }, [isMobile, servicesData.length]);
  
  if (isMobile) {
    return <ServicesMobile servicesData={servicesData} />;
  }
  
  const current = servicesData[currentIndex];
  
  const containerVariants = {
    enter: {
      opacity: 0,
      scale: 0.9,
      rotateX: -15
    },
    center: {
      opacity: 1,
      scale: 1,
      rotateX: 0,
      transition: {
        duration: 0.15,
        ease: [0.4, 0, 0.2, 1],
        staggerChildren: 0.01
      }
    },
    exit: {
      opacity: 0,
      scale: 1.1,
      rotateX: 15,
      transition: {
        duration: 0.1,
        ease: [0.4, 0, 0.2, 1]
      }
    }
  };
  
  const itemVariants = {
    enter: {
      y: 50,
      opacity: 0
    },
    center: {
      y: 0,
      opacity: 1,
      transition: {
        duration: 0.1,
        ease: [0.4, 0, 0.2, 1]
      }
    },
    exit: {
      y: -50,
      opacity: 0
    }
  };
  
  const logoVariants = {
    enter: {
      scale: 0,
      rotate: -180,
      opacity: 0
    },
    center: {
      scale: 1,
      rotate: 0,
      opacity: 1,
      transition: {
        duration: 0.15,
        ease: [0.4, 0, 0.2, 1]
      }
    },
    exit: {
      scale: 0,
      rotate: 180,
      opacity: 0
    }
  };
  
  return (
    <Container id="services">
      <PinSection ref={pinRef} $accent={current.accent}>
        <SectionTitle>Services</SectionTitle>
        
        <AnimatePresence mode="popLayout">
          <ServiceContent
            key={current.id}
            variants={containerVariants}
            initial="enter"
            animate="center"
            exit="exit"
          >
            <Content>
              <ServiceInfo>
                <Title 
                  $accent={current.accent}
                  variants={itemVariants}
                >
                  {current.title}
                </Title>
                <Description variants={itemVariants}>
                  {current.description}
                </Description>
                
                <ServiceDetails 
                  $accent={current.accent}
                  variants={itemVariants}
                >
                  <h3>What I Offer:</h3>
                  <ul>
                    {current.details.map((detail, i) => (
                      <motion.li 
                        key={i}
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: 0.015 * i }}
                      >
                        {detail}
                      </motion.li>
                    ))}
                  </ul>
                </ServiceDetails>
              </ServiceInfo>
              
              <LogoContainer 
                $accent={current.accent}
                variants={logoVariants}
              >
                {current.logo}
              </LogoContainer>
            </Content>
          </ServiceContent>
        </AnimatePresence>
        
        <ProgressIndicator>
          {servicesData.map((service, i) => (
            <ProgressDot
              key={i}
              $active={i === currentIndex}
              $accent={i === currentIndex ? current.accent : 'transparent'}
            />
          ))}
        </ProgressIndicator>
      </PinSection>
    </Container>
  );
};

export default Services;